const input = $input.first().json;
const action = input.action || 'list_contacts';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.lexware&cred_key=eq.lexware_api_token&select=cred_value',
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
});
if (!creds || !creds[0] || !creds[0].cred_value) return [{ json: { error: 'Lexware API token not configured.' } }];

const token = creds[0].cred_value;
const baseUrl = 'https://api.lexware.io/v1';
const headers = { 'Authorization': 'Bearer ' + token, 'Accept': 'application/json' };
const jsonHeaders = { ...headers, 'Content-Type': 'application/json' };

function parseAddress(addr) {
  if (!addr) return null;
  const a = { countryCode: 'DE' };
  const m = addr.match(/(\d{5})\s+(.+?)$/);
  if (m) {
    a.zip = m[1];
    a.city = m[2].trim();
    const st = addr.substring(0, m.index).replace(/,\s*$/, '').trim();
    if (st) a.street = st;
  } else {
    a.street = addr;
  }
  return a;
}

// === list_contacts ===
if (action === 'list_contacts') {
  try {
    let url = baseUrl + '/contacts?page=' + (input.page || '0') + '&size=25';
    const name = (input.name || '').trim();
    const email = (input.email || '').trim();
    if (name && name.length >= 3) url += '&name=' + encodeURIComponent(name);
    if (email && email.length >= 3) url += '&email=' + encodeURIComponent(email);
    if (input.customer === 'true') url += '&customer=true';
    if (input.vendor === 'true') url += '&vendor=true';
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) return [{ json: { result: 'No contacts found.' } }];
    let r = 'Contacts (page ' + data.number + '/' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const c of data.content) {
      let cn = c.company ? c.company.name : ((c.person?.firstName||'') + ' ' + (c.person?.lastName||'')).trim();
      r += '**' + cn + '**';
      const roles = [];
      if (c.roles?.customer) roles.push('Customer #' + (c.roles.customer.number||''));
      if (c.roles?.vendor) roles.push('Vendor #' + (c.roles.vendor.number||''));
      if (roles.length) r += ' (' + roles.join(', ') + ')';
      r += '\n';
      if (c.addresses?.billing?.[0]?.street) { const a=c.addresses.billing[0]; r+='  Addr: '+a.street+', '+(a.zip||'')+' '+(a.city||'')+'\n'; }
      const em = c.emailAddresses?.business?.[0] || c.emailAddresses?.office?.[0] || '';
      if (em) r += '  Email: ' + em + '\n';
      const ph = c.phoneNumbers?.business?.[0] || c.phoneNumbers?.mobile?.[0] || '';
      if (ph) r += '  Phone: ' + ph + '\n';
      r += '  ID: ' + c.id + '\n\n';
    }
    return [{ json: { result: r } }];
  } catch(e) { return [{ json: { error: 'list_contacts: ' + e.message } }]; }

// === get_contact ===
} else if (action === 'get_contact') {
  if (!input.id) return [{ json: { error: 'id is required.' } }];
  try {
    const c = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/contacts/' + input.id, headers });
    let r = '';
    if (c.company) {
      r += '**' + c.company.name + '** (Company)\n';
      if (c.company.contactPersons?.length) { r+='Contacts: '; for (const cp of c.company.contactPersons) r+=(cp.firstName?cp.firstName+' ':'')+cp.lastName+(cp.primary?' [primary]':'')+' '; r+='\n'; }
    } else if (c.person) {
      r += '**' + (c.person.firstName?c.person.firstName+' ':'') + c.person.lastName + '** (Person)\n';
    }
    const roles = [];
    if (c.roles?.customer) roles.push('Customer #'+(c.roles.customer.number||''));
    if (c.roles?.vendor) roles.push('Vendor #'+(c.roles.vendor.number||''));
    if (roles.length) r += 'Roles: ' + roles.join(', ') + '\n';
    if (c.addresses?.billing?.[0]) { const a=c.addresses.billing[0]; r+='Address: '+(a.street||'')+', '+(a.zip||'')+' '+(a.city||'')+', '+(a.countryCode||'')+'\n'; }
    for (const [cat,vals] of Object.entries(c.emailAddresses||{})) { if (Array.isArray(vals)&&vals.length) r+='Email: '+vals[0]+' ('+cat+')\n'; }
    for (const [cat,vals] of Object.entries(c.phoneNumbers||{})) { if (Array.isArray(vals)&&vals.length) r+='Phone: '+vals[0]+' ('+cat+')\n'; }
    if (c.note) r += 'Note: ' + c.note + '\n';
    r += '\nVersion: ' + c.version + '\nID: ' + c.id;
    return [{ json: { result: r } }];
  } catch(e) { return [{ json: { error: 'get_contact: ' + e.message } }]; }

// === create_company ===
} else if (action === 'create_company') {
  const cn = (input.companyName || '').trim();
  if (!cn) return [{ json: { error: 'companyName is required.' } }];
  try {
    const body = { version: 0, roles: { customer: {} }, company: { name: cn } };
    const cpn = (input.contactPersonName || '').trim();
    if (cpn) { const p=cpn.split(' '); body.company.contactPersons=[{lastName:p.pop(),primary:true}]; if(p.length) body.company.contactPersons[0].firstName=p.join(' '); }
    const em = (input.email || '').trim();
    if (em && em.includes('@')) body.emailAddresses = { business: [em] };
    const ph = (input.phone || '').trim();
    if (ph && ph.length >= 6) body.phoneNumbers = { business: [ph] };
    const street = (input.street || '').trim();
    const zip = (input.zip || '').trim();
    const city = (input.city || '').trim();
    if (street && zip && city) body.addresses = { billing: [{ street, zip, city, countryCode: 'DE' }] };
    const note = (input.note || '').trim();
    if (note) body.note = note;
    const d = await helpers.httpRequest({ method: 'POST', url: baseUrl + '/contacts', headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Company contact created. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'create_company: ' + e.message } }]; }

// === create_person ===
} else if (action === 'create_person') {
  const ln = (input.lastName || '').trim();
  if (!ln) return [{ json: { error: 'lastName is required.' } }];
  try {
    const body = { version: 0, roles: { customer: {} }, person: { lastName: ln } };
    const fn = (input.firstName || '').trim();
    if (fn) body.person.firstName = fn;
    const em = (input.email || '').trim();
    if (em && em.includes('@')) body.emailAddresses = { business: [em] };
    const ph = (input.phone || '').trim();
    if (ph && ph.length >= 6) body.phoneNumbers = { business: [ph] };
    const street = (input.street || '').trim();
    const zip = (input.zip || '').trim();
    const city = (input.city || '').trim();
    if (street && zip && city) body.addresses = { billing: [{ street, zip, city, countryCode: 'DE' }] };
    const note = (input.note || '').trim();
    if (note) body.note = note;
    const d = await helpers.httpRequest({ method: 'POST', url: baseUrl + '/contacts', headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Person contact created. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'create_person: ' + e.message } }]; }

// === update_address ===
} else if (action === 'update_address') {
  const id = (input.id||'').trim();
  const version = (input.version||'').trim();
  const street = (input.street||'').trim();
  const zip = (input.zip||'').trim();
  const city = (input.city||'').trim();
  if (!id||!version||!street||!zip||!city) return [{ json: { error: 'id, version, street, zip, and city are ALL required.' } }];
  try {
    const c = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/contacts/' + id, headers });
    const body = JSON.parse(JSON.stringify({ version: parseInt(version), roles: c.roles }));
    if (c.company) body.company = JSON.parse(JSON.stringify(c.company));
    if (c.person) body.person = JSON.parse(JSON.stringify(c.person));
    if (c.emailAddresses) body.emailAddresses = JSON.parse(JSON.stringify(c.emailAddresses));
    if (c.phoneNumbers) body.phoneNumbers = JSON.parse(JSON.stringify(c.phoneNumbers));
    if (c.note) body.note = c.note;
    body.addresses = { billing: [{ street: street, zip: zip, city: city, countryCode: 'DE' }] };
    await new Promise(r => setTimeout(r, 600));
    const d = await helpers.httpRequest({ method: 'PUT', url: baseUrl + '/contacts/' + id, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Address updated. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'update_address: ' + e.message } }]; }

// === update_email ===
} else if (action === 'update_email') {
  const id = (input.id||'').trim();
  const version = (input.version||'').trim();
  const email = (input.email||'').trim();
  if (!id||!version||!email) return [{ json: { error: 'id, version, and email are ALL required.' } }];
  try {
    const c = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/contacts/' + id, headers });
    const body = JSON.parse(JSON.stringify({ version: parseInt(version), roles: c.roles }));
    if (c.company) body.company = JSON.parse(JSON.stringify(c.company));
    if (c.person) body.person = JSON.parse(JSON.stringify(c.person));
    if (c.phoneNumbers) body.phoneNumbers = JSON.parse(JSON.stringify(c.phoneNumbers));
    if (c.addresses) body.addresses = JSON.parse(JSON.stringify(c.addresses));
    if (c.note) body.note = c.note;
    body.emailAddresses = { business: [email] };
    await new Promise(r => setTimeout(r, 600));
    const d = await helpers.httpRequest({ method: 'PUT', url: baseUrl + '/contacts/' + id, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Email updated. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'update_email: ' + e.message } }]; }

// === update_phone ===
} else if (action === 'update_phone') {
  const id = (input.id||'').trim();
  const version = (input.version||'').trim();
  const phone = (input.phone||'').trim();
  if (!id||!version||!phone) return [{ json: { error: 'id, version, and phone are ALL required.' } }];
  try {
    const c = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/contacts/' + id, headers });
    const body = JSON.parse(JSON.stringify({ version: parseInt(version), roles: c.roles }));
    if (c.company) body.company = JSON.parse(JSON.stringify(c.company));
    if (c.person) body.person = JSON.parse(JSON.stringify(c.person));
    if (c.emailAddresses) body.emailAddresses = JSON.parse(JSON.stringify(c.emailAddresses));
    if (c.addresses) body.addresses = JSON.parse(JSON.stringify(c.addresses));
    if (c.note) body.note = c.note;
    body.phoneNumbers = { business: [phone] };
    await new Promise(r => setTimeout(r, 600));
    const d = await helpers.httpRequest({ method: 'PUT', url: baseUrl + '/contacts/' + id, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Phone updated. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'update_phone: ' + e.message } }]; }

// === update_name ===
} else if (action === 'update_name') {
  const id = (input.id||'').trim();
  const version = (input.version||'').trim();
  const name = (input.name||'').trim();
  if (!id||!version||!name) return [{ json: { error: 'id, version, and name are ALL required.' } }];
  try {
    const c = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/contacts/' + id, headers });
    const body = JSON.parse(JSON.stringify({ version: parseInt(version), roles: c.roles }));
    if (c.company) { body.company = JSON.parse(JSON.stringify(c.company)); body.company.name = name; }
    if (c.person) { body.person = JSON.parse(JSON.stringify(c.person)); body.person.lastName = name; }
    if (c.emailAddresses) body.emailAddresses = JSON.parse(JSON.stringify(c.emailAddresses));
    if (c.phoneNumbers) body.phoneNumbers = JSON.parse(JSON.stringify(c.phoneNumbers));
    if (c.addresses) body.addresses = JSON.parse(JSON.stringify(c.addresses));
    if (c.note) body.note = c.note;
    await new Promise(r => setTimeout(r, 600));
    const d = await helpers.httpRequest({ method: 'PUT', url: baseUrl + '/contacts/' + id, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Name updated. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'update_name: ' + e.message } }]; }



// === list_articles ===
} else if (action === 'list_articles') {
  try {
    let url = baseUrl + '/articles?page=' + (input.page || '0') + '&size=25';
    const type = (input.type || '').trim();
    if (type) url += '&type=' + type;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) return [{ json: { result: 'No articles found.' } }];
    let r = 'Articles (page ' + data.number + '/' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const a of data.content) {
      r += '**' + a.title + '**';
      if (a.articleNumber) r += ' (#' + a.articleNumber + ')';
      r += '\n  Type: ' + a.type;
      if (a.unitName) r += ' | Unit: ' + a.unitName;
      if (a.price) r += ' | Price: ' + Number(a.price.netPrice||0).toFixed(2) + ' net (' + (a.price.taxRate||0) + '% tax)';
      r += '\n  ID: ' + a.id + '\n\n';
    }
    return [{ json: { result: r } }];
  } catch(e) { return [{ json: { error: 'list_articles: ' + e.message } }]; }

// === get_article ===
} else if (action === 'get_article') {
  if (!input.id) return [{ json: { error: 'id is required.' } }];
  try {
    const a = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/articles/' + input.id, headers });
    let r = '**' + a.title + '**';
    if (a.articleNumber) r += ' (#' + a.articleNumber + ')';
    r += '\nType: ' + a.type;
    if (a.description) r += '\nDescription: ' + a.description;
    if (a.unitName) r += '\nUnit: ' + a.unitName;
    if (a.price) {
      r += '\nNet Price: ' + Number(a.price.netPrice||0).toFixed(2);
      r += '\nGross Price: ' + Number(a.price.grossPrice||0).toFixed(2);
      r += '\nTax Rate: ' + (a.price.taxRate||0) + '%';
      r += '\nLeading Price: ' + (a.price.leadingPrice||'net');
    }
    r += '\nVersion: ' + a.version + '\nID: ' + a.id;
    return [{ json: { result: r } }];
  } catch(e) { return [{ json: { error: 'get_article: ' + e.message } }]; }

// === create_article ===
} else if (action === 'create_article') {
  const title = (input.title || '').trim();
  if (!title) return [{ json: { error: 'title is required.' } }];
  try {
    const netPriceRaw = (input.netPrice || '').trim();
    if (!netPriceRaw) return [{ json: { error: 'netPrice is required. Provide the net price as a number, e.g. 120 or 1600.50' } }];
    const netPrice = parseFloat(netPriceRaw);
    if (isNaN(netPrice)) return [{ json: { error: 'netPrice must be a number. Got: ' + netPriceRaw } }];
    const taxRate = (input.taxRate && input.taxRate.trim()) ? parseFloat(input.taxRate) : 19;
    const body = {
      title: title,
      type: (input.type || '').trim() || 'SERVICE',
      unitName: (input.unitName || '').trim() || 'Stück',
      price: {
        netPrice: isNaN(netPrice) ? 0 : netPrice,
        taxRate: isNaN(taxRate) ? 19 : taxRate,
        leadingPrice: 'NET'
      }
    };
    const desc = (input.description || '').trim();
    if (desc) body.description = desc;
    const artNr = (input.articleNumber || '').trim();
    if (artNr) body.articleNumber = artNr;
    const d = await helpers.httpRequest({ method: 'POST', url: baseUrl + '/articles', headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Article created. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) {
    const detail = e.response ? JSON.stringify(e.response.data || e.response.body || '').substring(0,300) : '';
    return [{ json: { error: 'create_article: ' + e.message + (detail ? ' Detail: ' + detail : '') } }];
  }

// === update_article ===
} else if (action === 'update_article') {
  const id = (input.id || '').trim();
  const version = (input.version || '').trim();
  const title = (input.title || '').trim();
  if (!id || !version || !title) return [{ json: { error: 'id, version, and title are ALL required. Use get_article first.' } }];
  try {
    // Aktuellen Artikel laden um fehlende Felder zu behalten
    const current = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/articles/' + id, headers });
    const body = {
      version: parseInt(version),
      title: title,
      type: (input.type || '').trim() || current.type || 'SERVICE',
      unitName: (input.unitName || '').trim() || current.unitName || 'Stück',
      price: {
        netPrice: (input.netPrice && input.netPrice.trim()) ? parseFloat(input.netPrice) : (current.price?.netPrice || 0),
        taxRate: (input.taxRate && input.taxRate.trim()) ? parseFloat(input.taxRate) : (current.price?.taxRate || 19),
        leadingPrice: current.price?.leadingPrice || 'net'
      }
    };
    const desc = (input.description || '').trim();
    if (desc) body.description = desc;
    else if (current.description) body.description = current.description;
    const artNr = (input.articleNumber || '').trim();
    if (artNr) body.articleNumber = artNr;
    else if (current.articleNumber) body.articleNumber = current.articleNumber;
    await new Promise(r => setTimeout(r, 600));
    const d = await helpers.httpRequest({ method: 'PUT', url: baseUrl + '/articles/' + id, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Article updated. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'update_article: ' + e.message } }]; }

// === delete_article ===
} else if (action === 'delete_article') {
  const id = (input.id || '').trim();
  if (!id) return [{ json: { error: 'id is required.' } }];
  try {
    await helpers.httpRequest({ method: 'DELETE', url: baseUrl + '/articles/' + id, headers });
    return [{ json: { result: 'Article deleted. ID: ' + id } }];
  } catch(e) { return [{ json: { error: 'delete_article: ' + e.message } }]; }



// === upload_voucher ===
} else if (action === 'upload_voucher') {
  const fileRef = (input.file_ref || '').trim();
  if (!fileRef) return [{ json: { error: 'file_ref is required. This is the file reference ID from the File Bridge.' } }];
  try {
    // File Bridge /forward Endpoint nutzen — der baut korrektes Multipart
    const d = await helpers.httpRequest({
      method: 'POST',
      url: 'http://file-bridge:3200/files/' + fileRef + '/forward',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        url: baseUrl + '/files',
        headers: { 'Authorization': 'Bearer ' + token, 'Accept': 'application/json' },
        file_field: 'file',
        form_fields: { type: 'voucher' }
      })
    });
    const result = d.response || d;
    const fileId = result.id || (typeof result === 'string' ? result : JSON.stringify(result));
    return [{ json: { result: 'Voucher uploaded to Lexware. Response: ' + JSON.stringify(result).substring(0,300) } }];
  } catch(e) { return [{ json: { error: 'upload_voucher: ' + e.message } }]; }



// === list_quotations ===
} else if (action === 'list_quotations') {
  try {
    const pg = (input.page || '').trim() || '0';
    let url = baseUrl + '/voucherlist?voucherType=quotation&page=' + pg + '&size=25&sort=voucherDate,DESC';
    const status = (input.status || '').trim();
    if (status) url += '&voucherStatus=' + status;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) return [{ json: { result: 'No quotations found.' } }];
    let r = 'Quotations (page ' + data.number + '/' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const q of data.content) {
      r += '**' + (q.voucherNumber || 'Draft') + '** — ' + (q.contactName || '?') + '\n';
      r += '  Date: ' + (q.voucherDate || '').split('T')[0] + ' | Status: ' + q.voucherStatus + ' | Total: ' + Number(q.totalAmount || 0).toFixed(2) + '\n';
      r += '  ID: ' + q.id + '\n\n';
    }
    return [{ json: { result: r } }];
  } catch(e) { const detail = e.response?.data ? JSON.stringify(e.response.data).substring(0,300) : ''; return [{ json: { error: 'list_quotations: ' + e.message + (detail ? ' | ' + detail : '') } }]; }

// === get_quotation ===
} else if (action === 'get_quotation') {
  if (!input.id) return [{ json: { error: 'id is required.' } }];
  try {
    const q = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/quotations/' + input.id, headers });
    let r = '**Quotation ' + (q.voucherNumber || 'Draft') + '**\n';
    if (q.address?.name) r += 'To: ' + q.address.name + '\n';
    if (q.address?.street) r += '  ' + q.address.street + ', ' + (q.address.zip||'') + ' ' + (q.address.city||'') + '\n';
    r += 'Date: ' + (q.voucherDate || '').split('T')[0] + '\n';
    if (q.expirationDate) r += 'Expires: ' + q.expirationDate.split('T')[0] + '\n';
    if (q.lineItems) {
      r += '\nLine Items:\n';
      for (const item of q.lineItems) {
        if (item.type === 'custom') {
          r += '  - ' + item.name + ' (x' + (item.quantity||1) + ')';
          if (item.unitPrice?.netAmount !== undefined) r += ' @ ' + Number(item.unitPrice.netAmount).toFixed(2);
          r += '\n';
        }
      }
    }
    if (q.totalPrice) {
      r += '\nTotal Net: ' + Number(q.totalPrice.totalNetAmount||0).toFixed(2);
      r += ' | Total Gross: ' + Number(q.totalPrice.totalGrossAmount||0).toFixed(2) + '\n';
    }
    r += '\nID: ' + q.id;
    return [{ json: { result: r } }];
  } catch(e) { return [{ json: { error: 'get_quotation: ' + e.message } }]; }

// === create_quotation ===
} else if (action === 'create_quotation') {
  const contactId = (input.contactId || '').trim();
  const lineItemsStr = (input.lineItems || '').trim();
  if (!contactId || !lineItemsStr) return [{ json: { error: 'contactId and lineItems are required.' } }];
  try {
    let items;
    try { items = JSON.parse(lineItemsStr); } catch(e) { return [{ json: { error: 'lineItems must be valid JSON array: ' + e.message } }]; }
    const lineItems = items.map(i => ({
      type: 'custom',
      name: i.name || i.title || 'Position',
      quantity: i.quantity || 1,
      unitName: i.unitName || i.unit || 'Stück',
      unitPrice: {
        currency: 'EUR',
        netAmount: i.unitPrice || i.netAmount || i.price || 0,
        taxRatePercentage: i.taxRate || i.taxRatePercentage || 19
      }
    }));
    // Datum als ISO-DateTime formatieren
    const vDateRaw = (input.voucherDate || '').trim() || new Date().toISOString().split('T')[0];
    const vDate = vDateRaw.includes('T') ? vDateRaw : vDateRaw + 'T00:00:00.000+02:00';
    // expirationDate: 30 Tage nach voucherDate
    const expDate = new Date(new Date(vDateRaw).getTime() + 30*24*60*60*1000).toISOString().split('T')[0] + 'T00:00:00.000+02:00';
    const body = {
      voucherDate: vDate,
      expirationDate: expDate,
      address: { contactId },
      lineItems,
      totalPrice: { currency: 'EUR' },
      taxConditions: { taxType: 'net' }
    };
    const intro = (input.introduction || '').trim();
    if (intro) body.introduction = intro;
    const remark = (input.remark || '').trim();
    if (remark) body.remark = remark;
    const finalize = (input.finalize || '').trim();
    const doFinalize = finalize !== 'false';
    let url = baseUrl + '/quotations';
    if (doFinalize) url += '?finalize=true';
    const d = await helpers.httpRequest({ method: 'POST', url, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Quotation created. ID: ' + d.id + ', Version: ' + d.version + (doFinalize ? ' (finalized)' : ' (draft)') } }];
  } catch(e) { const detail = e.response?.data ? JSON.stringify(e.response.data).substring(0,300) : ''; return [{ json: { error: 'create_quotation: ' + e.message + (detail ? ' | ' + detail : '') } }]; }

// === list_invoices ===
} else if (action === 'list_invoices') {
  try {
    const pgI = (input.page || '').trim() || '0';
    let url = baseUrl + '/voucherlist?voucherType=invoice&page=' + pgI + '&size=25&sort=voucherDate,DESC';
    const status = (input.status || '').trim();
    if (status) url += '&voucherStatus=' + status;
    const data = await helpers.httpRequest({ method: 'GET', url, headers });
    if (!data.content || data.content.length === 0) return [{ json: { result: 'No invoices found.' } }];
    let r = 'Invoices (page ' + data.number + '/' + data.totalPages + ', ' + data.totalElements + ' total):\n\n';
    for (const inv of data.content) {
      r += '**' + (inv.voucherNumber || 'Draft') + '** — ' + (inv.contactName || '?') + '\n';
      r += '  Date: ' + (inv.voucherDate || '').split('T')[0] + ' | Status: ' + inv.voucherStatus + ' | Total: ' + Number(inv.totalAmount || 0).toFixed(2) + '\n';
      if (inv.dueDate) r += '  Due: ' + inv.dueDate.split('T')[0] + '\n';
      r += '  ID: ' + inv.id + '\n\n';
    }
    return [{ json: { result: r } }];
  } catch(e) { const detail = e.response?.data ? JSON.stringify(e.response.data).substring(0,300) : ''; return [{ json: { error: 'list_invoices: ' + e.message + (detail ? ' | ' + detail : '') } }]; }

// === get_invoice ===
} else if (action === 'get_invoice') {
  if (!input.id) return [{ json: { error: 'id is required.' } }];
  try {
    const inv = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/invoices/' + input.id, headers });
    let r = '**Invoice ' + (inv.voucherNumber || 'Draft') + '**\n';
    if (inv.address?.name) r += 'To: ' + inv.address.name + '\n';
    if (inv.address?.street) r += '  ' + inv.address.street + ', ' + (inv.address.zip||'') + ' ' + (inv.address.city||'') + '\n';
    r += 'Date: ' + (inv.voucherDate || '').split('T')[0] + '\n';
    if (inv.dueDate) r += 'Due: ' + inv.dueDate.split('T')[0] + '\n';
    if (inv.lineItems) {
      r += '\nLine Items:\n';
      for (const item of inv.lineItems) {
        if (item.type === 'custom') {
          r += '  - ' + item.name + ' (x' + (item.quantity||1) + ')';
          if (item.unitPrice?.netAmount !== undefined) r += ' @ ' + Number(item.unitPrice.netAmount).toFixed(2);
          r += '\n';
        }
      }
    }
    if (inv.totalPrice) {
      r += '\nTotal Net: ' + Number(inv.totalPrice.totalNetAmount||0).toFixed(2);
      r += ' | Total Gross: ' + Number(inv.totalPrice.totalGrossAmount||0).toFixed(2) + '\n';
    }
    r += '\nID: ' + inv.id;
    return [{ json: { result: r } }];
  } catch(e) { return [{ json: { error: 'get_invoice: ' + e.message } }]; }

// === create_invoice ===
} else if (action === 'create_invoice') {
  const contactId = (input.contactId || '').trim();
  const lineItemsStr = (input.lineItems || '').trim();
  if (!contactId || !lineItemsStr) return [{ json: { error: 'contactId and lineItems are required.' } }];
  try {
    let items;
    try { items = JSON.parse(lineItemsStr); } catch(e) { return [{ json: { error: 'lineItems must be valid JSON array: ' + e.message } }]; }
    const lineItems = items.map(i => ({
      type: 'custom',
      name: i.name || i.title || 'Position',
      quantity: i.quantity || 1,
      unitName: i.unitName || i.unit || 'Stück',
      unitPrice: {
        currency: 'EUR',
        netAmount: i.unitPrice || i.netAmount || i.price || 0,
        taxRatePercentage: i.taxRate || i.taxRatePercentage || 19
      }
    }));
    const vDateRawI = (input.voucherDate || '').trim() || new Date().toISOString().split('T')[0];
    const vDateI = vDateRawI.includes('T') ? vDateRawI : vDateRawI + 'T00:00:00.000+02:00';
    const body = {
      voucherDate: vDateI,
      address: { contactId },
      lineItems,
      totalPrice: { currency: 'EUR' },
      taxConditions: { taxType: 'net' },
      shippingConditions: { shippingType: 'none' }
    };
    const intro = (input.introduction || '').trim();
    if (intro) body.introduction = intro;
    const remark = (input.remark || '').trim();
    if (remark) body.remark = remark;
    const finalize = (input.finalize || '').trim();
    const doFinalize = finalize !== 'false';
    let url = baseUrl + '/invoices';
    if (doFinalize) url += '?finalize=true';
    const d = await helpers.httpRequest({ method: 'POST', url, headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Invoice created. ID: ' + d.id + ', Version: ' + d.version + (doFinalize ? ' (finalized)' : ' (draft)') } }];
  } catch(e) { const detail = e.response?.data ? JSON.stringify(e.response.data).substring(0,300) : ''; return [{ json: { error: 'create_invoice: ' + e.message + (detail ? ' | ' + detail : '') } }]; }

// === create_invoice_from_quotation ===
} else if (action === 'create_invoice_from_quotation') {
  const quotationId = (input.quotationId || '').trim();
  if (!quotationId) return [{ json: { error: 'quotationId is required.' } }];
  try {
    const finalize = (input.finalize || '').trim();
    let url = baseUrl + '/invoices?precedingSalesVoucherId=' + quotationId;
    if (finalize === 'true') url += '&finalize=true';
    const d = await helpers.httpRequest({ method: 'POST', url, headers: jsonHeaders, body: '{}' });
    return [{ json: { result: 'Invoice from quotation created. ID: ' + d.id + ', Version: ' + d.version } }];
  } catch(e) { return [{ json: { error: 'create_invoice_from_quotation: ' + e.message } }]; }



// === download_invoice ===
} else if (action === 'download_invoice') {
  const id = (input.id || '').trim();
  if (!id) return [{ json: { error: 'id is required.' } }];
  try {
    // 0. Prüfen ob finalisiert
    const inv = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/invoices/' + id, headers });
    if (!inv.voucherNumber) return [{ json: { error: 'This invoice is still a draft. Finalize it first before downloading as PDF. Use create_invoice with finalize=true or finalize it manually in Lexware.' } }];
    // 1. PDF von Lexware holen
    const pdfResp = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/invoices/' + id + '/file',
      headers: { 'Authorization': 'Bearer ' + token, 'Accept': 'application/pdf' },
      encoding: 'arraybuffer',
      returnFullResponse: true
    });
    const pdfBuffer = Buffer.from(pdfResp.body);
    const base64 = pdfBuffer.toString('base64');

    // 2. In File Bridge speichern
    const bridge = await helpers.httpRequest({
      method: 'POST',
      url: 'http://file-bridge:3200/upload/base64',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        content_base64: base64,
        file_name: 'Rechnung-' + id.substring(0,8) + '.pdf',
        mime_type: 'application/pdf'
      })
    });

    // 3. send_file Marker zurückgeben
    return [{ json: { result: 'Invoice PDF ready. [send_file: http://file-bridge:3200/files/' + bridge.id + ']' } }];
  } catch(e) { return [{ json: { error: 'download_invoice: ' + e.message } }]; }

// === download_quotation ===
} else if (action === 'download_quotation') {
  const id = (input.id || '').trim();
  if (!id) return [{ json: { error: 'id is required.' } }];
  try {
    // 0. Prüfen ob finalisiert
    const quot = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/quotations/' + id, headers });
    if (!quot.voucherNumber) return [{ json: { error: 'This quotation is still a draft. Finalize it first before downloading as PDF. Finalize it manually in Lexware or create a new one with finalize=true.' } }];
    await new Promise(r => setTimeout(r, 600));
    // 1. PDF von Lexware holen
    const pdfResp = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/quotations/' + id + '/file',
      headers: { 'Authorization': 'Bearer ' + token, 'Accept': 'application/pdf' },
      encoding: 'arraybuffer',
      returnFullResponse: true
    });
    const pdfBuffer = Buffer.from(pdfResp.body);
    const base64 = pdfBuffer.toString('base64');

    // 2. In File Bridge speichern
    const bridge = await helpers.httpRequest({
      method: 'POST',
      url: 'http://file-bridge:3200/upload/base64',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        content_base64: base64,
        file_name: 'Angebot-' + id.substring(0,8) + '.pdf',
        mime_type: 'application/pdf'
      })
    });

    // 3. send_file Marker zurückgeben
    return [{ json: { result: 'Quotation PDF ready. [send_file: http://file-bridge:3200/files/' + bridge.id + ']' } }];
  } catch(e) { return [{ json: { error: 'download_quotation: ' + e.message } }]; }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: list_contacts, get_contact, create_company, create_person, update_address, update_email, update_phone, update_name, list_articles, get_article, create_article, update_article, delete_article.' } }];
}
